func listBackendSnippets(flags *rootFlags, limit, offset int) ([]Snippet, error) {
	lookupFlags := *flags
	lookupFlags.dryRun = false
	c, err := lookupFlags.newClient()
	if err != nil {
		return nil, err
	}
	body := map[string]any{
		"filter": map[string]any{"type": "snippet"},
		"limit":  limit,
		"offset": offset,
	}
	data, _, err := c.Post(snippetsListPath, body)
	if err != nil {
		return nil, addAuthLoginChromeHint(classifyAPIError(err, &lookupFlags))
	}
	snippets, err := parseSnippetList(data)
	if err != nil {
		return nil, fmt.Errorf("snippets list: parse backend response: %w", err)
	}
	return snippets, nil
}

// PATCH(greptile-snippets-pagination): paginate through every snippet page
// instead of capping at the first 100. The prior fetch passed limit=100,
// offset=0 and gave up - users with >100 snippets silently failed to find
// matches ranked beyond the first page. We page in chunks of 100 (the
// same chunk size the bundle uses) and stop when a response returns fewer
// rows than requested. The 10k hard ceiling guards against a runaway
// backend that always returns a full page.
func getBackendSnippet(flags *rootFlags, name string) (Snippet, int, error) {
	const pageSize = 100
	const hardCeiling = 10000
	var snippets []Snippet
	for offset := 0; ; offset += pageSize {
		page, err := listBackendSnippets(flags, pageSize, offset)
		if err != nil {
			return Snippet{}, 0, err
		}
		if len(page) == 0 {
			break
		}
		snippets = append(snippets, page...)
		if len(page) < pageSize {
			break
		}
		if len(snippets) >= hardCeiling {
			break
		}
	}
	matches := make([]Snippet, 0, 1)
	for _, snippet := range snippets {
		if snippet.Name == name {
			matches = append(matches, snippet)
		}
	}
	if len(matches) == 0 {
		return Snippet{}, 0, notFoundErr(fmt.Errorf("snippet %q not found", name))
	}
	sort.SliceStable(matches, func(i, j int) bool {
		return snippetModifiedUnix(matches[i]) > snippetModifiedUnix(matches[j])
	})
	return matches[0], len(matches), nil
}

func writeBackendSnippet(flags *rootFlags, identity snippetWriteIdentity, snippet Snippet, labelIDs []string) error {
	c, err := flags.newClient()
	if err != nil {
		return err
	}
	value := buildSnippetDraftValue(identity, snippet, labelIDs)
	payload := map[string]any{
		"doNotReturnValues": true,
		"writes": []map[string]any{{
			"path":  identity.Path,
			"value": value,
		}},
	}
	_, _, err = c.Post(snippetsWritePath, payload)
	if err != nil {
		return addAuthLoginChromeHint(classifyAPIError(err, flags))
	}
	return nil
}

func newSnippetWriteIdentity(flags *rootFlags, threadID, messageID, path string) (snippetWriteIdentity, error) {
	cfg, err := flags.loadConfig()
	if err != nil {
		return snippetWriteIdentity{}, fmt.Errorf("load config: %w", err)
	}
	email, err := cfg.ResolveActiveEmail()
	if err != nil || email == "" {
		return snippetWriteIdentity{}, fmt.Errorf("no active account; run 'auth login --disk' or pass --account <email>")
	}
	store := auth.NewStoreAt(cfg.TokenStorePath())
	acct, ok, err := store.Get(email)
	if err != nil {
		return snippetWriteIdentity{}, fmt.Errorf("load token store: %w", err)
	}
	if !ok {
		return snippetWriteIdentity{}, fmt.Errorf("account %s not in token store; run 'auth login --disk'", email)
	}
	if acct.UserID == "" {
		return snippetWriteIdentity{}, fmt.Errorf("account %s has no UserID (google provider id); run 'auth login --disk' to repopulate", email)
	}
	if threadID == "" {
		threadID = auth.NewDraftID()
	}
	if messageID == "" {
		messageID = threadID
	}
	if path == "" {
		path = fmt.Sprintf("users/%s/threads/%s/messages/%s/draft", acct.UserID, threadID, messageID)
	}
	return snippetWriteIdentity{
		Email:      email,
		UserID:     acct.UserID,
		FromName:   lookupAccountName(email),
		ThreadID:   threadID,
		MessageID:  messageID,
		Path:       path,
		Rfc822ID:   auth.NewRFC822ID(),
		Superhuman: auth.NewSuperhumanID(),
	}, nil
}

func buildSnippetDraftValue(identity snippetWriteIdentity, snippet Snippet, labelIDs []string) draftValue {
	now := time.Now()
	inputs := sendInputs{
		FromEmail:    identity.Email,
		FromName:     identity.FromName,
		Subject:      snippet.Subject,
		Body:         snippet.Body,
		HTMLBody:     false,
		DraftID:      identity.ThreadID,
		Rfc822ID:     identity.Rfc822ID,
		SuperhumanID: identity.Superhuman,
		Now:          now,
	}
	value := buildDraftValue(inputs)
	name := snippet.Name
	value.ID = identity.MessageID
	value.ThreadID = identity.ThreadID
	value.Name = &name
	value.LabelIDs = labelIDs
	value.Rfc822ID = identity.Rfc822ID
	return value
}

func resolveSnippetBody(cmd *cobra.Command, flags *rootFlags, name string, vars []string) (string, error) {
	snippet, duplicates, err := getBackendSnippet(flags, name)
	if err != nil {
		return "", err
	}
	if duplicates > 1 {
		fmt.Fprintf(cmd.ErrOrStderr(), "warning: multiple snippets named %q; using most recent\n", name)
	}
	return applySnippetVars(snippet.Body, vars)
}

func applySnippetVars(body string, vars []string) (string, error) {
	out := body
	for _, assignment := range vars {
		key, value, ok := strings.Cut(assignment, "=")
		if !ok || strings.TrimSpace(key) == "" {
			return "", fmt.Errorf("--var must be key=value, got %q", assignment)
		}
		out = strings.ReplaceAll(out, "{{"+strings.TrimSpace(key)+"}}", value)
	}
	return out, nil
}

func resolveSnippetBodyFromReader(r io.Reader) (string, error) {
	data, err := io.ReadAll(r)
	if err != nil {
		return "", err
	}
	return string(data), nil
}

func parseSnippetList(data []byte) ([]Snippet, error) {
	items, err := snippetListItems(data)
	if err != nil {
		return nil, err
	}
	snippets := make([]Snippet, 0, len(items))
	for _, item := range items {
		if snippet, ok := snippetFromMap(item); ok {
			snippets = append(snippets, snippet)
		}
	}
	return snippets, nil
}

func snippetListItems(data []byte) ([]map[string]any, error) {
	var direct []map[string]any
	if err := json.Unmarshal(data, &direct); err == nil {
		return direct, nil
	}
	var wrapped map[string]json.RawMessage
	if err := json.Unmarshal(data, &wrapped); err != nil {
		return nil, err
	}
	for _, key := range []string{"data", "threads", "items", "results"} {
		if raw, ok := wrapped[key]; ok {
			var nested []map[string]any
			if err := json.Unmarshal(raw, &nested); err == nil {
				return nested, nil
			}
		}
	}
	return []map[string]any{}, nil
}

func snippetFromMap(item map[string]any) (Snippet, bool) {
	source := item
	if value, ok := asMap(item["value"]); ok {
		source = mergeSnippetMaps(item, value)
	} else if draft, ok := asMap(item["draft"]); ok {
		source = mergeSnippetMaps(item, draft)
	} else if message, ok := asMap(item["message"]); ok {
		source = mergeSnippetMaps(item, message)
	}
	name := firstString(source, "name", "snippetName", "title")
	body := firstString(source, "body", "htmlBody", "text", "snippet")
	if name == "" && body == "" {
		return Snippet{}, false
	}
	threadID := firstString(source, "thread_id", "threadId", "threadID")
	id := firstString(source, "id", "draft_id", "draftId", "message_id", "messageId")
	if threadID == "" {
		threadID = id
	}
	path := firstString(source, "path")
	if id == "" {
		id = idFromSnippetPath(path)
	}
	if threadID == "" {
		threadID = threadIDFromSnippetPath(path)
	}
	return Snippet{
		ID:         id,
		ThreadID:   threadID,
		Path:       path,
		Name:       name,
		Subject:    firstString(source, "subject"),
		Body:       body,
		ModifiedAt: firstString(source, "modified_at", "modifiedAt", "updated_at", "updatedAt", "lastModifiedAt", "date", "clientCreatedAt"),
	}, true
}

func mergeSnippetMaps(outer, inner map[string]any) map[string]any {
	merged := make(map[string]any, len(outer)+len(inner))
	for k, v := range outer {
		merged[k] = v
	}
	for k, v := range inner {
		merged[k] = v
	}
	return merged
}

func asMap(v any) (map[string]any, bool) {
	m, ok := v.(map[string]any)
	return m, ok
}

func firstString(m map[string]any, keys ...string) string {
	for _, key := range keys {
		if value, ok := m[key]; ok {
			switch typed := value.(type) {
			case string:
				if typed != "" {
					return typed
				}
			case float64:
				return strconv.FormatInt(int64(typed), 10)
			}
		}
	}
	return ""
}

func snippetModifiedUnix(s Snippet) int64 {
	raw := strings.TrimSpace(s.ModifiedAt)
	if raw == "" {
		return 0
	}
	if n, err := strconv.ParseInt(raw, 10, 64); err == nil {
		if n > 1_000_000_000_000 {
			return n / 1000
		}
		return n
	}
	for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02T15:04:05.000Z"} {
		if parsed, err := time.Parse(layout, raw); err == nil {
			return parsed.Unix()
		}
	}
	return 0
}

func threadIDFromSnippetPath(path string) string {
	parts := strings.Split(path, "/")
	for i, part := range parts {
		if part == "threads" && i+1 < len(parts) {
			return parts[i+1]
		}
	}
	return ""
}

func idFromSnippetPath(path string) string {
	parts := strings.Split(path, "/")
	for i, part := range parts {
		if part == "messages" && i+1 < len(parts) {
			return parts[i+1]
		}
	}
	return ""
}

func maybeEmitSnippetMigrationHint(w io.Writer) error {
	localPath, markerPath, err := snippetMigrationPaths()
	if err != nil {
		return err
	}
	info, err := os.Stat(localPath)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return fmt.Errorf("checking local snippets migration file: %w", err)
	}
	if info.IsDir() || info.Size() == 0 {
		return nil
	}
	if _, err := os.Stat(markerPath); err == nil {
		return nil
	} else if err != nil && !os.IsNotExist(err) {
		return fmt.Errorf("checking snippets migration marker: %w", err)
	}
	fmt.Fprintf(w, "Found local snippets at %s. To migrate, run `snippets create --name <n> --body <b>` for each. Local file remains; not auto-uploaded.\n", localPath)
	if err := os.MkdirAll(filepath.Dir(markerPath), 0o700); err != nil {
		return fmt.Errorf("creating snippets migration marker dir: %w", err)
	}
	if err := os.WriteFile(markerPath, nil, 0o600); err != nil {
		return fmt.Errorf("writing snippets migration marker: %w", err)
	}
	return nil
}

func snippetMigrationPaths() (localPath, markerPath string, err error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", "", fmt.Errorf("resolving home dir: %w", err)
	}
	dir := filepath.Join(home, localSnippetMigrationStateSubdir)
	return filepath.Join(dir, localSnippetFilename), filepath.Join(dir, localSnippetMigrationMarkerName), nil
}

func truncateSnippet(s string, n int) string {
	s = strings.TrimSpace(s)
	if len(s) <= n {
		return s
	}
	return s[:n-3] + "..."
}
